const userQuestion = $('Telegram Trigger').first()?.json?.message?.text || 'No question provided';
const chatId = $('Telegram Trigger').first()?.json?.message?.chat?.id;

// Parse the raw array format from Google Sheets API
const rawData = $('Get Songs').first().json.values;
const headers = rawData[0]; // ["Year", "Movie", "Songs", "Singer", "Lyricist", "Director", "Actor"]
const rows = rawData.slice(1).map(row => {
  const obj = {};
  headers.forEach((h, i) => { obj[h] = row[i] || ''; });
  return obj;
});

const q = userQuestion.toLowerCase();

function getSingers(row) {
  return (row.Singer || '').split(',').map(s => s.trim()).filter(Boolean);
}
function rowMatchesSinger(row, name) {
  return getSingers(row).some(s => s.toLowerCase().includes(name.toLowerCase()));
}
function rowMatchesActor(row, name) {
  return (row.Actor || '').toLowerCase().includes(name.toLowerCase());
}
function isSoloSong(row) {
  return getSingers(row).length === 1;
}

const allSingers = [...new Set(rows.flatMap(r => getSingers(r)))];
const allActors  = [...new Set(rows.map(r => r.Actor).filter(Boolean))];

const mentionedSingers = allSingers.filter(s => q.includes(s.toLowerCase()));
const mentionedActors  = allActors.filter(a => q.includes(a.toLowerCase()));

let yearFrom = null, yearTo = null;
const decadeMatch = q.match(/(\d{4})s/);
const rangeMatch  = q.match(/(\d{4})\s*(to|-)\s*(\d{4})/);
const singleYear  = q.match(/\b(19|20)\d{2}\b/);

if (decadeMatch) {
  yearFrom = parseInt(decadeMatch[1]);
  yearTo   = yearFrom + 9;
} else if (rangeMatch) {
  yearFrom = parseInt(rangeMatch[1]);
  yearTo   = parseInt(rangeMatch[3]);
} else if (singleYear) {
  yearFrom = yearTo = parseInt(singleYear[0]);
}

let filtered = rows.filter(r => r.Songs && r.Year);

if (yearFrom) filtered = filtered.filter(r => parseInt(r.Year) >= yearFrom && parseInt(r.Year) <= (yearTo || yearFrom));

mentionedSingers.forEach(s => {
  filtered = filtered.filter(r => rowMatchesSinger(r, s));
});

mentionedActors.forEach(a => {
  filtered = filtered.filter(r => rowMatchesActor(r, a));
});

if (q.includes('solo')) {
  if (mentionedSingers.length > 0) {
    filtered = filtered.filter(r => isSoloSong(r) && rowMatchesSinger(r, mentionedSingers[0]));
  } else {
    filtered = filtered.filter(r => isSoloSong(r));
  }
}

let dataForLLM = '';

if (q.includes('top') && q.includes('year')) {
  const counts = {};
  rows.forEach(r => { if (r.Year) counts[r.Year] = (counts[r.Year] || 0) + 1; });
  const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
  dataForLLM = 'Songs per year (sorted):\n' + sorted.map(e => `${e[0]}: ${e[1]} songs`).join('\n');

} else if (q.includes('top') && q.includes('singer')) {
  const counts = {};
  rows.forEach(r => getSingers(r).forEach(s => { counts[s] = (counts[s] || 0) + 1; }));
  const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
  dataForLLM = 'Songs per singer (sorted):\n' + sorted.map(e => `${e[0]}: ${e[1]} songs`).join('\n');

} else if (q.includes('top') && q.includes('actor')) {
  const counts = {};
  rows.forEach(r => { if (r.Actor) counts[r.Actor] = (counts[r.Actor] || 0) + 1; });
  const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
  dataForLLM = 'Songs per actor (sorted):\n' + sorted.map(e => `${e[0]}: ${e[1]} songs`).join('\n');

} else {
  if (filtered.length === 0) {
    dataForLLM = 'No matching songs found for this query.';
  } else {
    dataForLLM = `Found ${filtered.length} matching songs:\n` +
      filtered.map(r => `${r.Year} | ${r.Movie} | ${r.Songs} | ${r.Singer} | ${r.Actor}`).join('\n');
  }
}

const prompt = `You are a Tamil film songs expert. Answer the user's question based only on the data provided below. Be concise.

DATA:
${dataForLLM}

QUESTION: ${userQuestion}

Answer clearly. Use a numbered list if listing multiple items.`;

return [{ json: { prompt, chatId } }];
